## 8. DYNAMIC PRICING IMPLEMENTATION

### Function-Based Pricing

```typescript
// Price as a function of request context
const dynamicPrice: DynamicPrice = (context: HTTPRequestContext) => {
  // Example: Price based on prompt length
  const body = context.req.body as { prompt?: string };
  const promptLength = body?.prompt?.length || 0;

  // Calculate price: 0.01 cUSD per 100 characters (minimum 0.01)
  const cUSDAmount = Math.max(
    1, // Minimum 0.01 cUSD (6 decimals: 10000)
    Math.ceil(promptLength / 100)
  ) * 10000; // Convert to atomic units (6 decimals)

  return {
    amount: cUSDAmount.toString(),
    asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3", // cUSD
  };
};

// Usage in middleware
app.use(
  paymentServer.middleware({
    "POST /api/prompt": {
      accepts: [{
        scheme: "exact",
        network: "eip155:42220",
        asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3",
        price: dynamicPrice,
        payTo: "0x...",
      }],
    },
  })
);
```

