// Facilitator signer (for verifying/settling payments)
interface FacilitatorEvmSigner {
  getAddresses(): Promise<string[]>; // For multi-key support
  readContract(params: ReadContractParams): Promise<unknown>;
  verifyTypedData(params: VerifyParams): Promise<boolean>;
  writeContract(params: WriteContractParams): Promise<string>;
  sendTransaction(params: SendTxParams): Promise<string>;
  waitForTransactionReceipt(txHash: string): Promise<TransactionReceipt>;
  getCode(address: string): Promise<string>;
}

// Helper functions
function toClientEvmSigner(account: LocalAccount, client: PublicClient): ClientEvmSigner
function toFacilitatorEvmSigner(client: PublicClient): FacilitatorEvmSigner
```

---

## 6. CLIENT-SIDE IMPLEMENTATION

### x402Client Setup

```typescript
import { x402Client } from "@x402/core/client";
import { createEvmClient } from "@x402/mechanisms/evm";

// Create client with EVM support
const paymentClient = x402Client.fromConfig({
  schemes: [
    createEvmClient({ 
      signer: clientEvmSigner 
    })
  ],
  policies: [], // Optional payment requirement filters
});

// Or manually register schemes
const client = new x402Client()
  .register("eip155:*", new ExactEvmClient(clientEvmSigner))
  .register("eip155:42220", new ExactEvmClient(celoSigner)); // Celo-specific
```

### Creating Payments

```typescript
// Create payment payload for a request
const paymentPayload = await client.createPaymentPayload({
  scheme: "exact",
  network: "eip155:42220", // Celo mainnet
  amount: "1000000000000000000", // 1 token (18 decimals)
  asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3", // cUSD
  payTo: "0x1234...",
  validAfter: Math.floor(Date.now() / 1000),
  validBefore: Math.floor(Date.now() / 1000) + 3600,
});
```

---

## 7. CELO-SPECIFIC CONFIGURATION

### Celo Chain IDs (CAIP-2 Format)

```typescript
// EVM Namespace: eip155

// Mainnet
const celoMainnet = "eip155:42220";

// Sepolia Testnet
const celoSepolia = "eip155:11142220";

// In payment requirements:
interface CeloPaymentOption {
  scheme: "exact";
  network: "eip155:42220" | "eip155:11142220";
  asset: string; // Token contract address on Celo
  price: Price | DynamicPrice;
  payTo: string;
}
```

### Celo USDC Configuration

```typescript
// cUSD (bridged) on Celo Mainnet
const CUSDC_ADDRESS = "0x765de816845861e75a25fca122bb6beb5a6868cc3";
const CUSDC_DECIMALS = 6;

// In payment option:
{
  scheme: "exact",
  network: "eip155:42220",
  asset: CUSDC_ADDRESS,
  price: {
    amount: "1000000", // 1 cUSD (6 decimals)
    asset: CUSDC_ADDRESS,
  },
  payTo: "0x...",
}
```

---

## 8. DYNAMIC PRICING IMPLEMENTATION

### Function-Based Pricing

```typescript
// Price as a function of request context
const dynamicPrice: DynamicPrice = (context: HTTPRequestContext) => {
  // Example: Price based on prompt length
  const body = context.req.body as { prompt?: string };
  const promptLength = body?.prompt?.length || 0;

  // Calculate price: 0.01 cUSD per 100 characters (minimum 0.01)
  const cUSDAmount = Math.max(
    1, // Minimum 0.01 cUSD (6 decimals: 10000)
    Math.ceil(promptLength / 100)
  ) * 10000; // Convert to atomic units (6 decimals)

  return {
    amount: cUSDAmount.toString(),
    asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3", // cUSD
  };
};

// Usage in middleware
app.use(
  paymentServer.middleware({
    "POST /api/prompt": {
      accepts: [{
        scheme: "exact",
        network: "eip155:42220",
        asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3",
        price: dynamicPrice,
        payTo: "0x...",
      }],
    },
  })
);
```

### Price Based on Route Parameters

```typescript
const paramBasedPrice: DynamicPrice = (context) => {
  const modelParam = context.params.model || "gpt-3.5";

  const priceMap: Record<string, number> = {
    "gpt-3.5": 1 * 10000,      // 0.01 cUSD
    "gpt-4": 10 * 10000,       // 0.10 cUSD
    "gpt-4-turbo": 50 * 10000, // 0.50 cUSD
  };

  return {
    amount: (priceMap[modelParam] || 1 * 10000).toString(),
    asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3",
  };
};
```

---

## 9. SUPPORTED PAYMENT KINDS AND VERSIONS

### Protocol Version Support

x402 supports both V1 (legacy) and V2 (modern):

```typescript
// V1: Simple network names (legacy)
const v1Example = "base-sepolia";

// V2: CAIP-2 identifiers (recommended)
const v2Example = "eip155:84532";

// Register both versions
server.register("eip155:*", evmSchemeV2);
server.registerSchemeV1("base-sepolia", evmSchemeV1);
```

### Exact Scheme Characteristics

```typescript
interface ExactSchemeConfig {
  scheme: "exact"; // Fixed amount payments
  network: "eip155:42220" | "eip155:11142220"; // Celo

  // EIP-3009 or Permit2 based on token capability
  // Server automatically selects best method
  assetTransferMethod: "eip3009" | "permit2";

  validAfter: number; // Unix timestamp
  validBefore: number; // Unix timestamp
}
```

---

## 10. SMART CONTRACT ADDRESSES (CONSTANTS)

### Permit2 & x402 Contracts

```typescript
// Canonical Permit2 (same on all EVM chains via CREATE2)
const PERMIT2_ADDRESS = "0x000000000022D473030F116dDEE9F6B43aC78BA3";

// x402 Exact Permit2 Proxy (for fixed amount payments)
const x402ExactPermit2ProxyAddress = "0x402085c248EeA27D92E8b30b2C58ed07f9E20001";

// x402 Upto Permit2 Proxy (for variable amount payments)
const x402UptoPerm it2ProxyAddress = "0x402039b3d6E6BEC5A02c2C9fd937ac17A6940002";

// Gas constants
const ERC20_APPROVE_GAS_LIMIT = 70000; // Standard approval gas
const DEFAULT_MAX_FEE_PER_GAS = 1000000000n; // 1 gwei
const DEFAULT_MAX_PRIORITY_FEE_PER_GAS = 100000000n; // 0.1 gwei
```

---

## 11. EXTENSION SUPPORT

### Available Extensions

```typescript
import {
  WithBazaar,
  WithSignInWithX,
  WithOfferReceipt,
  WithPaymentIdentifier,
  WithEip2612GasSponsoring,
  WithErc20ApprovalGasSponsoring,
} from "@x402/extensions";

// Extensions are composable
const clientWithExtensions = createEvmClient({ signer })
  .withBazaar()
  .withSignInWithX()
  .withPaymentIdentifier();
```

---

## 12. SUMMARY: TYPICAL IMPLEMENTATION FLOW

```typescript
// 1. SETUP: Create facilitator client with custom URL
const facilitator = new HTTPFacilitatorClient({
  url: "https://your-facilitator.com",
});

// 2. SERVER: Register EVM scheme for Celo
const paymentServer = new x402HTTPResourceServer(facilitator);
paymentServer.register("eip155:*", 
  new ExactEvmScheme(facilitatorEvmSigner)
);

// 3. MIDDLEWARE: Apply with dynamic pricing
app.use(
  paymentServer.middleware({
    "POST /api/generate": {
      accepts: [{
        scheme: "exact",
        network: "eip155:42220", // Celo mainnet
        asset: "0x765de816845861e75a25fca122bb6beb5a6868cc3", // cUSD
        price: (ctx) => calculatePrice(ctx.req.body), // Dynamic!
        payTo: receiverAddress,
      }],
      description: "AI content generation",
    },
  })
);

// 4. CLIENT: Create payment when receiving 402
const paymentClient = x402Client.fromConfig({
  schemes: [createEvmClient({ signer: clientEvmSigner })],
});

const payload = await paymentClient.createPaymentPayload({
  scheme: "exact",
  network: "eip155:42220",
  amount: priceInAtomicUnits,
  asset: CUSDC_ADDRESS,
  payTo: serverReceiver,
});

// 5. SUBMIT: Send request with payment
const response = await fetch("/api/generate", {
  method: "POST",
  body: JSON.stringify({ 
    prompt: "...",
    payment: payload 
  }),
});
```

---

## KEY NOTES FOR CELO IMPLEMENTATION

1. **Chain ID**: Use `eip155:42220` (mainnet) or `eip155:11142220` (Sepolia testnet)
2. **Token**: cUSD (`0x765de816845861e75a25fca122bb6beb5a6868cc3`) has 6 decimals
3. **Gasless**: EIP-3009 is truly gasless if token supports `transferWithAuthorization()`
4. **Dynamic Pricing**: Use `DynamicPrice` functions that receive `HTTPRequestContext`
5. **Custom Facilitator**: Pass `url` in `FacilitatorConfig` to specify your own facilitator
6. **Facilitator URL Default**: Defaults to `https://x402.org/facilitator` if not specified
7. **No Hono Package Found**: The GitHub search returned 0 results for Hono-specific implementation; use the core `x402HTTPResourceServer` with Hono directly

This comprehensive guide should give you everything needed to implement x402 v2 payments on Celo!

