```typescript
// ----- Model Pricing Configuration -----

export interface ModelPricing {
  inputPerMillionTokens: number;   // USD
  outputPerMillionTokens: number;  // USD
  defaultMaxOutputTokens: number;
}

export const MODEL_PRICING: Record<string, ModelPricing> = {
  "google/gemini-3.1-flash-image-preview": {
    inputPerMillionTokens: 0.50,
    outputPerMillionTokens: 3.00,
    defaultMaxOutputTokens: 1024,
  },
  "xiaomi/mimo-v2-omni": {
    inputPerMillionTokens: 0.40,
    outputPerMillionTokens: 2.00,
    defaultMaxOutputTokens: 2048,
  },
};

// ----- Token Estimation -----

/**
 * Estimates token count from text content.
 * Rule of thumb: ~4 characters per token for English text.
 */
export function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

/**
 * Extracts all text from a messages array, handling string content
 * and structured content arrays (TextContent, ImageContent, AudioContent).
 * 
 * For image_url content, adds a fixed token surcharge (e.g., 256 tokens
 * per image as a rough estimate for vision model overhead).
 * For audio content, estimates based on base64 data size.
 */
export function extractTextFromMessages(
  messages: Array<{ role: string; content: string | Array<{ type: string; text?: string; image_url?: unknown; input_audio?: { data: string } }> }>
): number {
  let totalTokens = 0;

  for (const msg of messages) {
    if (typeof msg.content === "string") {
      totalTokens += estimateTokens(msg.content);
    } else if (Array.isArray(msg.content)) {
      for (const part of msg.content) {
        if (part.type === "text" && part.text) {
          totalTokens += estimateTokens(part.text);
        } else if (part.type === "image_url") {
          // Vision models charge ~256 tokens per image as base overhead
          totalTokens += 256;
        } else if (part.type === "input_audio" && part.input_audio?.data) {
          // Rough estimate: base64 audio data, ~1 token per 100 bytes
          totalTokens += Math.ceil(part.input_audio.data.length / 100);
        }
      }
    }
  }

  return totalTokens;
}

/**
 * Extracts text from a simple prompt string (for image generation).
 */
export function extractTextFromPrompt(prompt: string): number {
  return estimateTokens(prompt);
}

// ----- Price Calculation -----

/** USDC has 6 decimals. We return a dollar string. */
export function calculatePrice(
  inputTokens: number,
  maxOutputTokens: number,
  pricing: ModelPricing,
): string {
  const inputCost = (inputTokens / 1_000_000) * pricing.inputPerMillionTokens;
  const outputCost = (maxOutputTokens / 1_000_000) * pricing.outputPerMillionTokens;
  const totalUsd = inputCost + outputCost;

  // Floor at $0.000001 (1 atomic USDC unit) to avoid zero-price requests
  const clamped = Math.max(totalUsd, 0.000001);

  // Format to 6 decimal places (matching USDC precision)
  return `$${clamped.toFixed(6)}`;
}
```

**Key design decisions in this file:**
- Token estimation uses the 4-char-per-token heuristic. This is intentionally conservative (slightly overestimates) which favors the service provider.
- Image content gets a flat 256-token surcharge per image -- standard for vision API pricing estimates.
- Audio content uses base64 data length as a proxy.
- The `calculatePrice` function returns a dollar string like `"$0.003456"` which is exactly what the x402 SDK `price` callback expects.
- Minimum price is 1 atomic USDC unit ($0.000001) to prevent free requests.

