import { HTTPFacilitatorClient } from "@x402/core/server";
import {
  MODEL_PRICING,
  extractTextFromMessages,
  extractTextFromPrompt,
  calculatePrice,
} from "../lib/pricing.js";
import type { MiddlewareHandler } from "hono";

// ----- Constants -----

const FACILITATOR_URL = "https://facilitator.ultravioletadao.xyz/";
const CELO_NETWORK = "eip155:42220";
const CELO_USDC = "0xcebA9300f2b948710d2653dD7B07f33A8B32118C";

// Model identifiers (must match what route handlers use)
const IMAGE_MODEL = "google/gemini-3.1-flash-image-preview";
const INFERENCE_MODEL = "xiaomi/mimo-v2-omni";

// ----- SDK Setup -----

function createX402Middleware(): MiddlewareHandler {
  // The payTo address -- where USDC payments are received.
  // Must be set as an environment variable.
  const payTo = process.env.X402_PAY_TO_ADDRESS;
  if (!payTo) {
    throw new Error("X402_PAY_TO_ADDRESS environment variable is not set");
  }

