    url: FACILITATOR_URL,
  });

  const resourceServer = new x402ResourceServer(facilitatorClient)
    .register(CELO_NETWORK, new ExactEvmScheme());

  return paymentMiddleware(
    {
      "POST /api/inference": {
        accepts: [
          {
            scheme: "exact",
            network: CELO_NETWORK,
            payTo,
            price: async (context) => {
              const bodyRaw = await context.adapter.getBody();
              const body = JSON.parse(bodyRaw);

              const pricing = MODEL_PRICING[INFERENCE_MODEL];
              if (!pricing) {
                return "$0.01"; // fallback
              }

              const inputTokens = extractTextFromMessages(body.messages || []);
              const maxOutputTokens = body.max_tokens ?? pricing.defaultMaxOutputTokens;

              return calculatePrice(inputTokens, maxOutputTokens, pricing);
            },
          },
        ],
        description: "AI inference via Xiaomi MiMo v2 Omni",
        mimeType: "application/json",
      },

      "POST /api/image-generation": {
        accepts: [
          {
            scheme: "exact",
            network: CELO_NETWORK,
            payTo,
            price: async (context) => {
              const bodyRaw = await context.adapter.getBody();
              const body = JSON.parse(bodyRaw);

              const pricing = MODEL_PRICING[IMAGE_MODEL];
              if (!pricing) {
                return "$0.01"; // fallback
              }

              // Image generation: the prompt is the input,
              // output tokens default applies (image generation response)
              const inputTokens = extractTextFromPrompt(body.prompt || "");
              const maxOutputTokens = pricing.defaultMaxOutputTokens;

              return calculatePrice(inputTokens, maxOutputTokens, pricing);
            },
          },
        ],
        description: "Image generation via Gemini 3.1 Flash Image Preview",
        mimeType: "application/json",
      },
    },
    resourceServer,
  );
}

export { createX402Middleware };
